    public required MusRef StemSet { get; init; }
    public required AssetMusicLayer Layer { get; init; }
    public required double Bpm { get; init; }
    public required string TimeSignature { get; init; }
    public required long LengthBars { get; init; }
    /// <summary>Drives stinger key-tag matching (Music SAD §2.3).</summary>
    public string? Key { get; init; }
    public bool? Loop { get; init; }
}

public sealed record AssetSfx
{
    /// <summary>Maps to a concurrency group + bus (Music SAD §2.5).</summary>
    public required string Category { get; init; }
    /// <summary>Round-robin siblings share this group id.</summary>
    public SfxRef? VariationGroup { get; init; }
    public required AssetSfxAttenuation Attenuation { get; init; }
}

public sealed record AssetEncode
{
    public AssetEncodeTier? Tier { get; init; }
    public bool? Preload { get; init; }
}

public sealed record Asset
{
    public required AssetId Id { get; init; }
    /// <summary>Drives import preset (art), encode tier (audio), and budget row selection. Art classes map to the Art SAD §2.3 preset table; audio classes to Music SAD §4.2.</summary>
    public required AssetClass Class { get; init; }
    /// <summary>LFS source file path, pack-root-relative under assets/ (pack-local per A-15 / D-31).</summary>
    public required string Source { get; init; }
    /// <summary>Additional source files for multi-file assets (texture sets, stem sessions).</summary>
    public IReadOnlyList<string>? ExtraSources { get; init; }
    /// <summary>SPDX expression; CI allowlist per TD-09.</summary>
    public required AssetLicense License { get; init; }
    /// <summary>TD-09 provenance record. Lint L022 requires completeness before pack/release builds.</summary>
    public required AssetProvenance Provenance { get; init; }
    /// <summary>Declared per-asset budget figures, checked against the Art PRD §2.1/§2.3/§2.4 class caps by lints L070-L072 (validate_content.py). Optional: until the LFS source drop, sidecars may omit it and only the schema/provenance gates apply; once declared, every field is enforced against the PRD row for `class`. The binary-parsing budget validator (Art SAD §4.2, tools/validate_asset_budgets.py, pygltflib) supersedes these declarations once .glb sources land — these fields are the authoring-time declaration the sidecar carries in the meantime.</summary>
    public AssetBudget? Budget { get; init; }
    public AssetImportHints? ImportHints { get; init; }
    /// <summary>Greybox contract snapshot for 1:1 art-pass swaps (Art SAD §6); written at greybox merge.</summary>
    public AssetContractEnvelope? ContractEnvelope { get; init; }
    /// <summary>Tiers ai/cc0/cc_by cannot merge as pending (Art SAD §3.2).</summary>
    public AssetRestyleStatus? RestyleStatus { get; init; }
    /// <summary>Style-gate sign-offs (two-reviewer rule); written by the review bot, not self-attested.</summary>
    public IReadOnlyList<string>? ReviewedBy { get; init; }
    /// <summary>Forge palette/browser filter tags (TLS-02).</summary>
    public IReadOnlyList<string>? Tags { get; init; }
    public AssetLoudness? Loudness { get; init; }
    /// <summary>Required for music_stem / music_stinger classes; feeds ZoneMusicPlayer stream metadata.</summary>
    public AssetMusic? Music { get; init; }
    /// <summary>Required for sfx / ui_sound / ambience_emitter classes.</summary>
    public AssetSfx? Sfx { get; init; }
    public AssetEncode? Encode { get; init; }
}

